"use strict";(self.webpackChunkdst_api_webdocs=self.webpackChunkdst_api_webdocs||[]).push([[2849],{61688:e=>{e.exports=JSON.parse('{"tag":{"label":"utility","permalink":"/dst-api-webdocs/docs/tags/utility","allTagsPath":"/dst-api-webdocs/docs/tags","count":38,"items":[{"id":"game-scripts/components/appraisable","title":"Appraisable","description":"Provides a pluggable appraisal mechanism for entities, allowing custom logic to determine whether a target can be appraised and what happens when appraisal occurs.","permalink":"/dst-api-webdocs/docs/game-scripts/components/appraisable"},{"id":"game-scripts/prefabs/armor_bramble","title":"Armor Bramble","description":"A wearable armor item that triggers thorn-based retaliation effects when the wearer is blocked or attacks, conditional on skill tree activation.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/armor_bramble"},{"id":"game-scripts/components/attackdodger","title":"Attackdodger","description":"Manages attack dodging logic including cooldown state and custom dodge/can-dodge behavior callbacks for an entity.","permalink":"/dst-api-webdocs/docs/game-scripts/components/attackdodger"},{"id":"game-scripts/components/battery","title":"Battery","description":"Manages whether an entity can be used as a power source and tracks usage callbacks for gameplay interactions.","permalink":"/dst-api-webdocs/docs/game-scripts/components/battery"},{"id":"game-scripts/prefabs/blinkfocus_marker","title":"Blinkfocus Marker","description":"A temporary, non-persistent marker entity used to visualize the maximum range of a blink-based ability (e.g., Wigfrid\'s Battle Truce).","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/blinkfocus_marker"},{"id":"game-scripts/components/bottler","title":"Bottler","description":"Provides a mechanism to bottle certain entities, invoking a customizable callback when the action succeeds.","permalink":"/dst-api-webdocs/docs/game-scripts/components/bottler"},{"id":"game-scripts/components/closeinspector","title":"Closeinspector","description":"Adds a tag to an entity and provides hooks for custom inspect target and inspect point validation logic, typically used to restrict or customize inspector interactions.","permalink":"/dst-api-webdocs/docs/game-scripts/components/closeinspector"},{"id":"game-scripts/components/distancetracker","title":"Distancetracker","description":"Tracks the distance an entity travels between update frames by recording its position and computing Euclidean displacement.","permalink":"/dst-api-webdocs/docs/game-scripts/components/distancetracker"},{"id":"game-scripts/components/erasablepaper","title":"Erasablepaper","description":"Manages the conversion of a paper item into a configurable number of erasure\u4ea7\u7269 (e.g., papyrus), handling stack splitting and item distribution.","permalink":"/dst-api-webdocs/docs/game-scripts/components/erasablepaper"},{"id":"game-scripts/components/farmtiller","title":"Farmtiller","description":"Provides functionality to till soil at a given point in the world.","permalink":"/dst-api-webdocs/docs/game-scripts/components/farmtiller"},{"id":"game-scripts/prefabs/fishingnetvisualizer","title":"Fishingnetvisualizer","description":"A visual proxy entity that displays a boat net animation and shadow, used to visually represent fishing nets placed by players or entities.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/fishingnetvisualizer"},{"id":"game-scripts/components/fuelmaster","title":"Fuelmaster","description":"Manages fuel-burning multiplier bonuses for entities that consume fuel, such as fire sources or lanterns.","permalink":"/dst-api-webdocs/docs/game-scripts/components/fuelmaster"},{"id":"game-scripts/components/ghostlyelixir","title":"Ghostlyelixir","description":"Handles the application of ghostly elixir effects to a target entity, consuming the item upon successful application.","permalink":"/dst-api-webdocs/docs/game-scripts/components/ghostlyelixir"},{"id":"game-scripts/prefabs/halloweenpotion_common","title":"Halloweenpotion Common","description":"Provides utility functions for spawning and attaching Halloween-themed particle effects (firepuffs) to targets.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/halloweenpotion_common"},{"id":"game-scripts/components/healer","title":"Healer","description":"Applies healing to a target entity and consumes the healer item upon use.","permalink":"/dst-api-webdocs/docs/game-scripts/components/healer"},{"id":"game-scripts/prefabs/junk_pile_common","title":"Junk pile common","description":"Provides shared loot generation and dependency tracking logic for junk pile entities in DST.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/junk_pile_common"},{"id":"game-scripts/components/lighter","title":"Lighter","description":"Enables an entity to ignite burnable targets by calling Ignite on their burnable component.","permalink":"/dst-api-webdocs/docs/game-scripts/components/lighter"},{"id":"game-scripts/components/lunarsupernovaburning","title":"Lunarsupernovaburning","description":"Applies and manages damage and visual effects for the Alter Guardian\'s lunar supernova ability during Phase 4.","permalink":"/dst-api-webdocs/docs/game-scripts/components/lunarsupernovaburning"},{"id":"game-scripts/components/magiciantool","title":"Magiciantool","description":"Manages the usage lifecycle of magical tools by tracking user context and invoking custom callbacks when tools are started or stopped being used.","permalink":"/dst-api-webdocs/docs/game-scripts/components/magiciantool"},{"id":"game-scripts/prefabs/retrofit_archiveteleporter","title":"Retrofit Archiveteleporter","description":"A utility prefab used to generate and link a pair of teleporter wormholes in the Blue Forest region or at a specified location, replacing an existing marker entity.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/retrofit_archiveteleporter"},{"id":"game-scripts/prefabs/retrofit_fumaroleteleporter","title":"Retrofit Fumaroleteleporter","description":"Spawns a pair of linked wormholes to retrofit fumarole teleporter functionality in the game world, primarily for connecting cave zones via Tier4 tasks.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/retrofit_fumaroleteleporter"},{"id":"game-scripts/prefabs/saddlehorn","title":"Saddlehorn","description":"A consumable tool that removes saddles from beefalo and other animals, with limited durability and weapon functionality.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/saddlehorn"},{"id":"game-scripts/prefabs/skilltree_defs","title":"Skilltree Defs","description":"Provides the data structure and validation logic for character-specific skill trees, including connection rules, locks, and helper utilities for modders.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/skilltree_defs"},{"id":"game-scripts/components/spdamageutil","title":"Spdamageutil","description":"A singleton utility for managing and calculating special damage types and their interaction with special defenses across entities.","permalink":"/dst-api-webdocs/docs/game-scripts/components/spdamageutil"},{"id":"game-scripts/prefabs/spider_whistle","title":"Spider Whistle","description":"A consumable item that summons spiders from dens and wakes up sleeping spiders within range, while granting temporary buffs to nearby spider followers.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/spider_whistle"},{"id":"game-scripts/map/stack","title":"Stack","description":"A utility class implementing a generic LIFO stack data structure for storing and retrieving ordered values.","permalink":"/dst-api-webdocs/docs/game-scripts/map/stack"},{"id":"game-scripts/components/teleportedoverride","title":"Teleportedoverride","description":"Stores custom destination functions for teleportation overrides on an entity.","permalink":"/dst-api-webdocs/docs/game-scripts/components/teleportedoverride"},{"id":"game-scripts/components/toggleableitem","title":"Toggleableitem","description":"Manages the toggle state (on/off) of an item and executes a user-defined callback when toggled.","permalink":"/dst-api-webdocs/docs/game-scripts/components/toggleableitem"},{"id":"game-scripts/components/treegrowthsolution","title":"Treegrowthsolution","description":"Applies growth progression to a target tree entity, consuming the solution item after use.","permalink":"/dst-api-webdocs/docs/game-scripts/components/treegrowthsolution"},{"id":"game-scripts/prefabs/wagboss_util","title":"Wagboss Util","description":"Utility module for managing lunar arena mechanics including fissures, lunar burn damage, and supernova line-of-sight blocking.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/wagboss_util"},{"id":"game-scripts/components/walkingplankuser","title":"Walkingplankuser","description":"Manages a player\'s or entity\'s current mounting state on a walking plank.","permalink":"/dst-api-webdocs/docs/game-scripts/components/walkingplankuser"},{"id":"game-scripts/components/waterproofer","title":"Waterproofer","description":"Prevents an entity\'s inventory item from accumulating moisture and adds the `waterproofer` tag.","permalink":"/dst-api-webdocs/docs/game-scripts/components/waterproofer"},{"id":"game-scripts/prefabs/waterpump","title":"Waterpump","description":"A functional entity that channels water in a circular area, launching water projectiles when used; breaks upon being hammered and extinguishes flames.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/waterpump"},{"id":"game-scripts/components/waxable","title":"Waxable","description":"Manages waxing interactions for an entity, including tag state and callback-based waxing logic.","permalink":"/dst-api-webdocs/docs/game-scripts/components/waxable"},{"id":"game-scripts/prefabs/wendy_resurrectiongrave","title":"Wendy Resurrectiongrave","description":"Manages a special resurrection altar for Wendy that allows linking to a player and consuming health to enable resurrection of fallen allies.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/wendy_resurrectiongrave"},{"id":"game-scripts/prefabs/willow_ember_common","title":"Willow Ember Common","description":"Provides shared utility functions for handling willow embers, including detection, spawning, and target selection logic.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/willow_ember_common"},{"id":"game-scripts/components/worker","title":"Worker","description":"Tracks which actions an entity can perform and their relative effectiveness.","permalink":"/dst-api-webdocs/docs/game-scripts/components/worker"},{"id":"game-scripts/prefabs/wortox_soul_common","title":"Wortox Soul Common","description":"Provides shared utility functions for Wortox\'s soul-based mechanics, including healing nearby players, spawning souls on death, and determining valid soul sources.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/wortox_soul_common"}],"unlisted":false}}')}}]);